
CREATE TABLE IF NOT EXISTS public.academic_performance (id uuid NOT NULL DEFAULT gen_random_uuid(), student_id uuid, subject text NOT NULL, term text NOT NULL, session text NOT NULL, score numeric DEFAULT 0, grade text, remark text, ca_score numeric DEFAULT 0, exam_score numeric DEFAULT 0, last_updated timestamp with time zone DEFAULT now(), school_id uuid);
