CREATE TABLE IF NOT EXISTS public.ticket_messages (id uuid NOT NULL DEFAULT gen_random_uuid(), school_id uuid NOT NULL, ticket_id uuid NOT NULL, sender_user_id uuid NOT NULL, body text NOT NULL DEFAULT ''::text, attachment_url text, created_at timestamp with time zone NOT NULL DEFAULT now());
CREATE TABLE IF NOT EXISTS public.tickets (id uuid NOT NULL DEFAULT gen_random_uuid(), school_id uuid NOT NULL, student_user_id uuid NOT NULL, created_by_parent_id uuid NOT NULL, category_id uuid, target_type text NOT NULL, target_user_id uuid, subject text NOT NULL, status text NOT NULL DEFAULT 'open'::text, priority text NOT NULL DEFAULT 'normal'::text, created_at timestamp with time zone NOT NULL DEFAULT now(), updated_at timestamp with time zone NOT NULL DEFAULT now());
CREATE TABLE IF NOT EXISTS public.timetable (id uuid NOT NULL DEFAULT gen_random_uuid(), class_name text NOT NULL, subject text NOT NULL, teacher_id uuid, day text NOT NULL, period_index integer NOT NULL, start_time time without time zone, end_time time without time zone, status text DEFAULT 'Draft'::text, created_at timestamp with time zone DEFAULT now(), updated_at timestamp with time zone DEFAULT now(), school_id uuid NOT NULL, class_id uuid, branch_id uuid);
CREATE TABLE IF NOT EXISTS public.transactions (id uuid NOT NULL DEFAULT uuid_generate_v4(), school_id uuid NOT NULL, transaction_type text, category text NOT NULL, amount numeric NOT NULL, description text, transaction_date date DEFAULT CURRENT_DATE, created_by uuid, created_at timestamp with time zone DEFAULT now());
CREATE TABLE IF NOT EXISTS public.transport_buses (id uuid NOT NULL DEFAULT uuid_generate_v4(), school_id uuid, driver_name text, plate_number text, capacity integer, status text DEFAULT 'active'::text, created_at timestamp with time zone DEFAULT now(), name text, route_name text, branch_id uuid);
CREATE TABLE IF NOT EXISTS public.user_branch_access (id uuid NOT NULL DEFAULT gen_random_uuid(), user_id uuid NOT NULL, branch_id uuid NOT NULL, school_id uuid NOT NULL, role text DEFAULT 'staff'::text, created_at timestamp with time zone DEFAULT now());
CREATE TABLE IF NOT EXISTS public.user_role_assignments (id uuid NOT NULL DEFAULT gen_random_uuid(), school_id uuid NOT NULL, user_id uuid NOT NULL, role_id uuid NOT NULL, is_active boolean NOT NULL DEFAULT true, assigned_by uuid, assigned_at timestamp with time zone NOT NULL DEFAULT now());
CREATE TABLE IF NOT EXISTS public.user_security_events (id uuid NOT NULL DEFAULT gen_random_uuid(), user_id uuid NOT NULL, school_id uuid, event_type text NOT NULL, metadata jsonb NOT NULL DEFAULT '{}'::jsonb, created_at timestamp with time zone NOT NULL DEFAULT now());
CREATE TABLE IF NOT EXISTS public.users (id uuid NOT NULL, school_id uuid, email text NOT NULL, full_name text, role text, created_at timestamp with time zone DEFAULT now(), avatar_url text, name text, branch_id uuid, staff_id text, custom_id text, updated_at timestamp with time zone DEFAULT now(), is_active boolean DEFAULT true, password_hash text, email_verified boolean DEFAULT false, school_generated_id text);
CREATE TABLE IF NOT EXISTS public.virtual_class_sessions (id uuid NOT NULL DEFAULT gen_random_uuid(), teacher_id uuid NOT NULL, class_id uuid, subject text NOT NULL, topic text, start_time timestamp with time zone DEFAULT now(), end_time timestamp with time zone, status text DEFAULT 'active'::text, meeting_link text, created_at timestamp with time zone DEFAULT now(), school_id uuid);
CREATE TABLE IF NOT EXISTS public.virtual_classes (id uuid NOT NULL DEFAULT uuid_generate_v4(), school_id uuid NOT NULL, teacher_id uuid, class_id uuid, subject_id uuid, title text NOT NULL, description text, meeting_url text, scheduled_at timestamp with time zone, duration_minutes integer DEFAULT 60, status text DEFAULT 'scheduled'::text, recording_url text, created_at timestamp with time zone DEFAULT now());
CREATE TABLE IF NOT EXISTS public.visitor_logs (id bigint NOT NULL, school_id uuid, visitor_name text NOT NULL, visitor_phone text, visitor_email text, purpose text, host_name text, id_type text, id_number text, vehicle_info text, check_in_time timestamp with time zone DEFAULT now(), check_out_time timestamp with time zone, qr_code text, verification_status text DEFAULT 'Unverified'::text, photo_url text, created_at timestamp with time zone DEFAULT now());
CREATE TABLE IF NOT EXISTS public.volunteer_signups (id uuid NOT NULL DEFAULT gen_random_uuid(), opportunity_id uuid, parent_user_id uuid NOT NULL, student_user_id uuid, school_id uuid NOT NULL, branch_id uuid, created_at timestamp with time zone DEFAULT now(), updated_at timestamp with time zone DEFAULT now(), status text DEFAULT 'Pending'::text);
CREATE TABLE IF NOT EXISTS public.volunteering_opportunities (id uuid NOT NULL DEFAULT gen_random_uuid(), school_id uuid NOT NULL, title text NOT NULL, description text, date date, time text, location text, created_at timestamp with time zone DEFAULT now(), updated_at timestamp with time zone DEFAULT now(), role text, status text DEFAULT 'Open'::text, spots_available integer DEFAULT 0, spots_filled integer DEFAULT 0, branch_id uuid);
